import"./ticker-BxUDbM2L.js";import{i as a}from"./country-page-CK6BdUjw.js";import"./utils-Owvk3OYq.js";import"./breadcrumbs-CxxVGuAV.js";a({countryCode:"BH",currency:"BHD",flag:"🇧🇭",nameEn:"Bahrain",nameAr:"البحرين",fixedPeg:!1,decimals:3,timezone:"Asia/Bahrain",relatedCountries:[{file:"uae.html",nameEn:"UAE",nameAr:"الإمارات",flag:"🇦🇪"},{file:"saudi-arabia.html",nameEn:"Saudi Arabia",nameAr:"السعودية",flag:"🇸🇦"},{file:"kuwait.html",nameEn:"Kuwait",nameAr:"الكويت",flag:"🇰🇼"},{file:"qatar.html",nameEn:"Qatar",nameAr:"قطر",flag:"🇶🇦"},{file:"oman.html",nameEn:"Oman",nameAr:"عُمان",flag:"🇴🇲"},{file:"egypt.html",nameEn:"Egypt",nameAr:"مصر",flag:"🇪🇬"}],faqEn:[{q:"What is today's gold price in Bahrain?",a:"The Bahraini Dinar (BHD) is pegged to the US Dollar at a fixed rate of 0.376 BHD per USD, making it one of the highest-value currencies in the GCC. Gold gram prices in BHD appear numerically small but represent significant real value. Prices are updated every 90 seconds."},{q:"Where can I buy gold in Bahrain?",a:"Gold City in Manama's city centre is the primary hub for gold trading in Bahrain, offering a wide selection of jewellery and bullion. Bahrain City Centre Mall and Seef Mall are also popular destinations with reputable gold retailers."},{q:"Is gold taxed in Bahrain?",a:"Bahrain introduced a 10% Value Added Tax (VAT) in 2019. Investment-grade gold (such as bars and coins meeting purity standards) is typically VAT-exempt, while gold jewellery is subject to the full 10% VAT rate."},{q:"What karats are most common in Bahrain?",a:"21K and 22K are the most popular karats for jewellery in Bahrain. Traditional Gulf-style pieces are predominantly 21K, while 22K is common for Indian-style jewellery. 24K gold is available for investment purposes."}],faqAr:[{q:"ما هو سعر الذهب اليوم في البحرين؟",a:"يرتبط الدينار البحريني (BHD) بالدولار الأمريكي بسعر صرف ثابت قدره 0.376 دينار لكل دولار، مما يجعله من أعلى عملات مجلس التعاون الخليجي قيمةً. تبدو أسعار الذهب بالغرام منخفضةً من الناحية الرقمية، غير أنها تعكس قيمةً حقيقيةً كبيرة. يتم تحديث الأسعار كل 90 ثانية."},{q:"أين يمكنني شراء الذهب في البحرين؟",a:"تُعدّ مدينة الذهب في وسط المنامة المحور الرئيسي لتجارة الذهب في البحرين، وتوفر تشكيلةً واسعة من المجوهرات والسبائك. كما يُعدّ مجمع البحرين سيتي سنتر ومجمع سيف مول من الوجهات الشهيرة التي تضم تجار ذهب موثوقين."},{q:"هل يُفرض ضريبة على الذهب في البحرين؟",a:"طبّقت البحرين ضريبة القيمة المضافة (VAT) بنسبة 10% في عام 2019. الذهب الاستثماري (كالسبائك والعملات التي تستوفي معايير النقاء) معفى عادةً من ضريبة القيمة المضافة، في حين تخضع مجوهرات الذهب لنسبة الـ10% كاملةً."},{q:"ما هي العيارات الأكثر شيوعاً في البحرين؟",a:"يُعدّ عيار 21 وعيار 22 الأكثر شيوعاً للمجوهرات في البحرين. تسود القطع التقليدية الخليجية بعيار 21، فيما يشيع عيار 22 في المجوهرات ذات الطابع الهندي. ويتوفر عيار 24 للأغراض الاستثمارية."}]});
